\begin{equation}\label{stat:slower-start-left} y \in (-\infty,\infty) \Longrightarrow ((Q^\epsilon D^\epsilon)\ast y) \in (-\infty,\widehat{y}_+)\,,\end{equation}
\begin{equation}\label{stat:slower-between-left} y \in (\widehat{y}_-,\infty) \Longrightarrow ((Q^\epsilon D^\epsilon)\ast y) \in (\widehat{y}_c,\infty)\,,\end{equation}
\begin{equation}\label{stat:faster-between-left} y \notin (\widetilde{y}_-,\infty) \Longrightarrow ((Q^\epsilon D^\epsilon)\ast y) \notin (\widetilde{y}_c,\infty)\,.\end{equation}.
